                  onMouseEnter={(e) => {
                    e.currentTarget.style.backgroundColor = "#fdd";
                    e.currentTarget.style.borderColor = "#c33";
                  }}
                  onMouseLeave={(e) => {
                    e.currentTarget.style.backgroundColor = "#fee";
                    e.currentTarget.style.borderColor = "#fcc";
                  }}
                >
                  ✕
                </button>
              </>
            )}
          </div>
        </div>
      </div>
    );
  };

  return (
    <div style={{ backgroundColor: "var(--bg)", paddingBottom: "40px" }}>
      {/* Page Header */}
      <div style={{
        paddingBottom: "40px",
        borderBottom: "1px solid var(--border)",
        marginBottom: "40px"
      }}>
        <h1 style={{
          fontSize: "32px",
          fontWeight: 800,
          color: "var(--text)",
          margin: "0 0 8px 0",
          letterSpacing: "-0.5px"
        }}>
