                  fontWeight: 600,
                  border: "1px solid var(--border)",
                  borderRadius: "8px",
                  backgroundColor: "var(--bg)",
                  color: "var(--text)",
                  cursor: "pointer",
                  minWidth: 200,
                  transition: "all 0.2s",
                  outline: "none"
                }}
                onFocus={(e) => {
