                onBook={() => bookNow(v._id, v.status)}
                onEdit={() => navigate(`/vehicles/edit/${v._id}`)}
                onDelete={() => onDelete(v._id)}
                onViewDetails={() => navigate(`/vehicles/${v._id}`)}
