      </div>

      <style>{`
        @keyframes fadeIn {
          from { opacity: 0; transform: translateY(10px); }
          to { opacity: 1; transform: translateY(0); }
        }
        @media (max-width: 768px) {
          div[style*="gridTemplateColumns: repeat(auto-fill"] {
            grid-template-columns: 1fr !important;
          }
          div[style*="gridTemplateColumns: repeat(auto-fit"] {
            grid-template-columns: 1fr !important;
          }
        }
      `}</style>
    </div>
  );
}

// Image Carousel Component
function ImageCarousel({ vehicle, isCompact = false, onIndexChange }) {
  const [currentIndex, setCurrentIndex] = useState(0);

  // Get formatted image URLs
  const images = useMemo(() => {
    return (vehicle?.images || []).map((img) => ({
      url: img.url.startsWith("http") ? img.url : `http://localhost:8070${img.url}`,
      filename: img.filename,
    }));
  }, [vehicle]);

  const currentImage = images.length > 0 ? images[currentIndex] : null;

  // Auto-play carousel
  useEffect(() => {
    if (images.length <= 1) return;

    const interval = setInterval(() => {
      setCurrentIndex((prev) => (prev + 1) % images.length);
    }, 4000); // Change image every 4 seconds

    return () => clearInterval(interval);
  }, [images.length]);

  const goToPrevious = () => {
    const newIndex = currentIndex === 0 ? images.length - 1 : currentIndex - 1;
    setCurrentIndex(newIndex);
    onIndexChange(newIndex);
  };

  const goToNext = () => {
    const newIndex = (currentIndex + 1) % images.length;
    setCurrentIndex(newIndex);
    onIndexChange(newIndex);
  };

  const aspectRatio = isCompact ? "16 / 10" : "4 / 3";
  const buttonSize = isCompact ? 28 : 36;
  const buttonFontSize = isCompact ? "16px" : "18px";

  if (images.length === 0) {
    return (
      <div style={{ width: "100%", aspectRatio, background: "#f3f4f6", display: "grid", placeItems: "center", color: "#6b7280", fontSize: "12px", fontWeight: "600" }}>
        No Photos
      </div>
    );
  }

  return (
    <div style={{ position: "relative", width: "100%", aspectRatio, background: "#f3f4f6", overflow: "hidden", display: "flex", alignItems: "center", justifyContent: "center" }}>
      {/* Main Image */}
      {currentImage && (
        <img
          src={currentImage.url}
          alt={`${vehicle.brand} ${currentIndex + 1}`}
          style={{ width: "100%", height: "100%", objectFit: "cover", display: "block" }}
        />
      )}

      {/* Previous Button */}
      {images.length > 1 && (
        <button
          onClick={goToPrevious}
          style={{
            position: "absolute",
            left: 6,
            top: "50%",
            transform: "translateY(-50%)",
            background: "rgba(0, 0, 0, 0.5)",
            color: "white",
            border: "none",
            width: buttonSize,
            height: buttonSize,
            borderRadius: 3,
            cursor: "pointer",
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
            fontSize: buttonFontSize,
            fontWeight: "bold",
            transition: "background 0.2s",
            zIndex: 10,
          }}
          onMouseEnter={(e) => e.target.style.background = "rgba(0, 0, 0, 0.8)"}
          onMouseLeave={(e) => e.target.style.background = "rgba(0, 0, 0, 0.5)"}
        >
          ‹
        </button>
      )}

      {/* Next Button */}
      {images.length > 1 && (
        <button
          onClick={goToNext}
          style={{
            position: "absolute",
            right: 6,
            top: "50%",
            transform: "translateY(-50%)",
            background: "rgba(0, 0, 0, 0.5)",
            color: "white",
            border: "none",
            width: buttonSize,
            height: buttonSize,
            borderRadius: 3,
            cursor: "pointer",
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
            fontSize: buttonFontSize,
            fontWeight: "bold",
            transition: "background 0.2s",
            zIndex: 10,
          }}
          onMouseEnter={(e) => e.target.style.background = "rgba(0, 0, 0, 0.8)"}
          onMouseLeave={(e) => e.target.style.background = "rgba(0, 0, 0, 0.5)"}
        >
          ›
        </button>
      )}

      {/* Image Counter */}
      {images.length > 1 && (
        <div
          style={{
            position: "absolute",
            bottom: 6,
            right: 6,
            background: "rgba(0, 0, 0, 0.6)",
            color: "white",
            padding: "3px 6px",
            borderRadius: 3,
            fontSize: "11px",
            fontWeight: "600",
            zIndex: 10,
          }}
        >
          {currentIndex + 1} / {images.length}
        </div>
      )}

      {/* Image Indicators (Dots) */}
      {images.length > 1 && (
        <div
          style={{
            position: "absolute",
            bottom: 6,
            left: "50%",
            transform: "translateX(-50%)",
            display: "flex",
            gap: 6,
            zIndex: 10,
          }}
        >
          {images.map((_, idx) => (
            <button
              key={idx}
              onClick={() => {
                setCurrentIndex(idx);
                onIndexChange(idx);
              }}
              style={{
                width: 6,
                height: 6,
                borderRadius: "50%",
                background: idx === currentIndex ? "white" : "rgba(255, 255, 255, 0.5)",
                border: "none",
                cursor: "pointer",
                transition: "background 0.2s",
              }}
              title={`Go to image ${idx + 1}`}
            />
          ))}
        </div>
      )}
    </div>
  );
}

function InfoRow({ label, value, clamp }) {
  return (
    <div style={{ display: "flex", justifyContent: "space-between", gap: 14 }}>
      <div style={{ opacity: 0.65, fontWeight: 800, fontSize: "13px" }}>{label}</div>
      <div
        style={{
          fontWeight: 900,
          textAlign: "right",
          maxWidth: 220,
          overflow: "hidden",
          textOverflow: "ellipsis",
          whiteSpace: clamp ? "nowrap" : "normal",
          color: "var(--navy)",
          fontSize: "13px",
        }}
